const BREAKPOINTS={DESKTOP:1280,TABLET:1024,SMALL_TABLET:768,MOBILE:320,MOBILE_LANDSCAPE_HEIGHT:415,MEDIUM_HEIGHT:720};function widthPlus(t){return`(min-width: ${t}px)`}function widthMinus(t){return`(max-width: ${t-.1}px)`}function widthHalfInterval(t,E){return widthPlus(t)+" and "+widthMinus(E)}function heightPlus(t){return`(min-height: ${t}px)`}function heightMinus(t){return`(max-height: ${t-.1}px)`}function heightHalfInterval(t,E){return heightPlus(t)+" and "+heightMinus(E)}const MEDIA_QUERIES={DESKTOP_PLUS:widthPlus(BREAKPOINTS.DESKTOP),TABLET:widthHalfInterval(BREAKPOINTS.TABLET,BREAKPOINTS.DESKTOP),SMALL_TABLET_PLUS:widthPlus(BREAKPOINTS.SMALL_TABLET),SMALL_TABLET:widthHalfInterval(BREAKPOINTS.SMALL_TABLET,BREAKPOINTS.TABLET),MOBILE:widthHalfInterval(BREAKPOINTS.MOBILE,BREAKPOINTS.SMALL_TABLET),MEDIUM_HEIGHT:heightPlus(BREAKPOINTS.MEDIUM_HEIGHT),MOBILE_LANDSCAPE_HEIGHT:heightPlus(BREAKPOINTS.MOBILE_LANDSCAPE_HEIGHT)};module.exports={BREAKPOINTS:BREAKPOINTS,MEDIA_QUERIES:MEDIA_QUERIES,widthHalfInterval:widthHalfInterval,widthPlus:widthPlus,widthMinus:widthMinus,heightHalfInterval:heightHalfInterval,heightPlus:heightPlus,heightMinus:heightMinus};